// Node 1: Einfache Metadaten-Sammlung
const items = [];

for (const item of $input.all()) {
  const extractedData = item.json;
  const originalFile = $('Google Drive - Get All Files').item.json;

  // Timestamp für Dateinamen
  const timestamp = new Date();
  const timestampStr = timestamp.toISOString().replace(/[:.]/g, '-').split('.')[0];

  // Normalisierte Dateinamen
  const baseFilename = extractedData.name.replace(/\.[^/.]+$/, "")
    .replace(/[^a-zA-Zа-яёА-ЯЁ0-9\-_\s]/g, '')
    .replace(/\s+/g, '_')
    .substring(0, 80); // Kurzer Name

  const textFilename = `extracted_${baseFilename}_${timestampStr}.txt`;

  // Nur wichtige Metadaten
  const metadata = {
    original_file: {
      filename: originalFile.name,
      google_drive_id: originalFile.id,
      mime_type: originalFile.mimeType,
      file_size: originalFile.size || 'Неизвестно',
      last_modified: originalFile.modifiedTime,
      web_view_link: originalFile.webViewLink
    },
    extraction: {
      timestamp: timestamp.toISOString(),
      timestamp_local: timestamp.toLocaleString('ru-RU', { 
        timeZone: 'Europe/Moscow',
        year: 'numeric',
        month: '2-digit', 
        day: '2-digit',
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit'
      }),
      method: 'Автоматическое извлечение текста'
    },
    content: {
      text_length: extractedData.extractedText.length,
      word_count: extractedData.extractedText.split(/\s+/).filter(w => w.length > 0).length,
      line_count: extractedData.extractedText.split('\n').length,
      content_hash: extractedData.contentHash,
      language: 'Русский',
      encoding: 'UTF-8'
    },
    document_info: {
      title: extractedData.documentStructure?.title || 'Не определен',
      has_structure: !!(extractedData.documentStructure?.sections?.length || extractedData.documentStructure?.headings?.length)
    }
  };

  items.push({
    textFilename: textFilename,
    metadata: metadata,
    extractedText: extractedData.extractedText,
    originalFile: originalFile
  });
}

return items;

// Node 2: Formatierung der Text-Datei (nur Text + Metadaten)
const items = [];

for (const item of $input.all()) {
  const { textFilename, metadata, extractedText } = item.json;

  // Einfache, klare Formatierung
  let content = ``;

  // Header
  content += `ИЗВЛЕЧЕННЫЙ ТЕКСТ ИЗ ДОКУМЕНТА\n`;
  content += `${'='.repeat(60)}\n\n`;

  // Metadaten
  content += `ИНФОРМАЦИЯ О ФАЙЛЕ:\n`;
  content += `  Исходный файл: ${metadata.original_file.filename}\n`;
  content += `  Google Drive ID: ${metadata.original_file.google_drive_id}\n`;
  content += `  Тип файла: ${metadata.original_file.mime_type}\n`;
  content += `  Размер файла: ${formatFileSize(metadata.original_file.file_size)}\n`;
  content += `  Последнее изменение: ${metadata.original_file.last_modified}\n`;
  content += `  Ссылка: ${metadata.original_file.web_view_link}\n\n`;

  content += `ИНФОРМАЦИЯ ОБ ИЗВЛЕЧЕНИИ:\n`;
  content += `  Дата и время: ${metadata.extraction.timestamp_local}\n`;
  content += `  Метод: ${metadata.extraction.method}\n`;
  content += `  Хеш содержимого: ${metadata.content.content_hash}\n\n`;

  content += `СТАТИСТИКА ТЕКСТА:\n`;
  content += `  Размер: ${metadata.content.text_length.toLocaleString()} символов\n`;
  content += `  Слов: ${metadata.content.word_count.toLocaleString()}\n`;
  content += `  Строк: ${metadata.content.line_count.toLocaleString()}\n`;
  content += `  Язык: ${metadata.content.language}\n`;
  content += `  Кодировка: ${metadata.content.encoding}\n`;

  if (metadata.document_info.title !== 'Не определен') {
    content += `  Заголовок: ${metadata.document_info.title}\n`;
  }

  content += `\n${'='.repeat(60)}\n`;
  content += `СОДЕРЖАНИЕ ДОКУМЕНТА\n`;
  content += `${'='.repeat(60)}\n\n`;

  // Полный extrahierter Text
  content += extractedText;

  // Footer
  content += `\n\n${'='.repeat(60)}\n`;
  content += `Файл создан: ${new Date().toLocaleString('ru-RU')}\n`;
  content += `Система: N8N Text Extraction Pipeline\n`;
  content += `${'='.repeat(60)}`;

  // Hilfsfunktion für Dateigröße
  function formatFileSize(bytes) {
    if (!bytes || bytes === 'Неизвестно') return 'Неизвестно';
    const sizes = ['Б', 'КБ', 'МБ', 'ГБ'];
    const i = Math.floor(Math.log(bytes) / Math.log(1024));
    return Math.round(bytes / Math.pow(1024, i) * 100) / 100 + ' ' + sizes[i];
  }

  // Zu Base64 konvertieren
  const base64Content = Buffer.from(content, 'utf-8').toString('base64');

  items.push({
    textFilename: textFilename,
    content: content,
    base64Content: base64Content,
    fileSize: content.length,
    metadata: metadata
  });
}

return items;
